// Prepare list of 'jobs' to process.
// Each job = { kind: 'news'|'fallback', item: {...} }
const input = $('When Executed By Workflow').first().json;
const mode = input.mode || 'FALLBACK';
const run_id = input.run_id || `run_${Date.now()}`;
const selected = Array.isArray(input.selected_items) ? input.selected_items : [];
const fallbacks = Array.isArray(input.fallback_items) ? input.fallback_items : [];

if (mode === 'MONITOR_ONLY' || mode === 'HARD_STOP') {
  // No content packages are produced for these modes — emit an empty job list
  return [];
}

const jobs = [];
if (mode === 'FULL_NEWS') {
  selected.slice(0,3).forEach(it => jobs.push({ kind:'news', item: it }));
} else if (mode === 'HYBRID') {
  selected.slice(0,3).forEach(it => jobs.push({ kind:'news', item: it }));
  const need = 3 - jobs.length;
  fallbacks.slice(0, need).forEach(it => jobs.push({ kind:'fallback', item: it }));
} else if (mode === 'FALLBACK') {
  fallbacks.slice(0,3).forEach(it => jobs.push({ kind:'fallback', item: it }));
}
return jobs.map((j, idx) => ({ json: { ...j, job_idx: idx, run_id, mode } }));

// Runs once per job item. $json is the current job.
const cfg = $('Config').first().json;
const job = $json;
const isFallback = job.kind === 'fallback';
const item = job.item || {};

const system = `Sei un editor esperto di AI e business. Scrivi in italiano, prima persona, tono semplice, moderno, moderatamente opinato, non hype, non corporate, non guru, non troppo tecnico. Target: imprenditori, PMI, liberi professionisti. Obiettivo: posizionamento + lead generation futura. Output: SOLO JSON valido, senza testo fuori dal JSON.`;

const schema = {
  claim_sheet: {
    what_happened: 'string',
    who: 'string',
    when: 'string',
    why_it_matters: 'string',
    business_implication: 'string',
    italy_relevance: 'string',
    what_we_cannot_claim: 'string',
    source_type: 'official|trusted_media|monitored_account|leak|evergreen',
    is_leak: 'boolean',
    confidence_reason: 'string'
  },
  angle: {
    entrepreneur_relevance: 'string',
    sme_relevance: 'string',
    solo_pro_relevance: 'string',
    practical_takeaway: 'string',
    anti_hype_framing: 'string'
  },
  instagram: {
    hook: 'string (max 12 parole, forte)',
    script: 'string (30-45s parlato, 80-130 parole, ritmo semplice, prima persona)',
    caption: 'string (2-4 frasi)',
    cta: 'string (1 frase, concreta)'
  },
  linkedin: {
    post: 'string (classic post, 120-220 parole, clean)',
    take_personal: 'string (1-2 frasi di opinione personale)'
  },
  qc: {
    factual_safety_ok: 'boolean',
    leak_labeling_ok: 'boolean',
    audience_fit_ok: 'boolean',
    simplicity_ok: 'boolean',
    usefulness_ok: 'boolean',
    non_hype_ok: 'boolean',
    platform_fit_ok: 'boolean',
    status: 'ready|review|raw|discarded',
    confidence_label: 'high|medium|low'
  },
  meta: {
    topic: 'string',
    why_it_matters: 'string (1 frase sintetica)',
    why_it_can_work: 'string (1 frase)',
    recording_time_estimate: 'string (es: 30-40s)'
  }
};

const rulesLeak = `Se la fonte è un leak o un rumor non confermato, is_leak=true e ogni testo Instagram/LinkedIn DEVE etichettare esplicitamente ("leak", "rumor non confermato") e non presentare come fatto confermato. In caso di confidence basso o fatti non verificabili, status massimo = review (mai ready).`;

let userPayload;
if (!isFallback) {
  userPayload = {
    mode: job.mode,
    input_kind: 'news',
    news_item: {
      title: item.title,
      url: item.url,
      source_name: item.source_name,
      source_tier: item.source_tier,
      published_at: item.published_at,
      summary: item.summary,
      primary_topic: item.primary_topic,
      notes: item.notes || null
    },
    schema,
    rules_leak: rulesLeak,
    required: 'Genera un pacchetto editoriale completo. Se non riesci a garantire utilità e veridicità, status=discarded.'
  };
} else {
  userPayload = {
    mode: job.mode,
    input_kind: 'fallback',
    fallback_topic: {
      title: item.title || item.fallback_title,
      category: item.category,
      angle: item.angle,
      target: item.target
    },
    schema,
    rules_leak: rulesLeak,
    required: 'Genera un pacchetto evergreen/trend/practical coerente col topic fallback. Nessuna claim di news fresca.'
  };
}

const body = {
  model: cfg.modelMain,
  temperature: 0.4,
  max_tokens: 2200,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: JSON.stringify(userPayload) }
  ]
};

return { json: { ...job, openrouter_body: body } };

// Runs once per item (LLM response). Pair with original job via $itemIndex.
function safeParse(s){
  if (!s) return null;
  let t = String(s).trim();
  const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (m) t = m[1].trim();
  try { return JSON.parse(t); } catch(e){}
  const a=t.indexOf('{'),b=t.lastIndexOf('}');
  if (a>=0&&b>a){ try{ return JSON.parse(t.slice(a,b+1)); }catch(e){} }
  return null;
}
const inp = $json;
const jobsAll = $('Prepare Jobs').all().map(i => i.json);
const job = jobsAll[$itemIndex] || jobsAll[0] || {};
const run_id = job.run_id || 'unknown';
const mode = job.mode || 'FALLBACK';
const kind = job.kind || 'news';
const srcItem = job.item || {};

let pkgRaw = null;
const choices = (inp.choices) ? inp.choices : ((inp.body && inp.body.choices) ? inp.body.choices : null);
if (choices && choices[0]) {
  const content = choices[0].message?.content;
  pkgRaw = safeParse(content);
}

if (!pkgRaw) {
  // LLM failed or bad JSON — produce a minimal discarded package
  return {
    json: {
      content_id: `c_${run_id}_${Date.now()}_${Math.floor(Math.random()*1000)}`,
      run_id,
      item_id: srcItem.item_id || null,
      mode,
      platform_pair: 'instagram+linkedin',
      status: 'discarded',
      confidence_label: 'low',
      topic: srcItem.title || srcItem.fallback_title || 'n/a',
      why_it_matters: '',
      why_it_can_work: '',
      recording_time_estimate: '',
      instagram: { hook:'', script:'', caption:'', cta:'' },
      linkedin: { post:'', take_personal:'' },
      source_name: srcItem.source_name || (kind==='fallback' ? 'internal_fallback' : ''),
      source_url: srcItem.url || '',
      prompt_version: $('Config').first().json.promptVersion || 'v1',
      qc_reason: 'invalid_llm_json_or_no_response'
    }
  };
}

const cs = pkgRaw.claim_sheet || {};
const ig = pkgRaw.instagram || {};
const li = pkgRaw.linkedin || {};
const qc = pkgRaw.qc || {};
const meta = pkgRaw.meta || {};

// Hard rule: if leak and leak_labeling_ok !== true → downgrade
let status = qc.status || 'raw';
let confidence = qc.confidence_label || 'low';
if (cs.is_leak === true && qc.leak_labeling_ok !== true) status = 'review';
if (confidence === 'low' && status === 'ready') status = 'review';

return {
  json: {
    content_id: `c_${run_id}_${Date.now()}_${Math.floor(Math.random()*1000)}`,
    run_id,
    item_id: srcItem.item_id || null,
    mode,
    platform_pair: 'instagram+linkedin',
    status,
    confidence_label: confidence,
    topic: meta.topic || srcItem.title || srcItem.fallback_title || 'n/a',
    why_it_matters: meta.why_it_matters || cs.why_it_matters || '',
    why_it_can_work: meta.why_it_can_work || '',
    recording_time_estimate: meta.recording_time_estimate || '30-40s',
    instagram: {
      hook: ig.hook || '',
      script: ig.script || '',
      caption: ig.caption || '',
      cta: ig.cta || ''
    },
    linkedin: {
      post: li.post || '',
      take_personal: li.take_personal || ''
    },
    source_name: srcItem.source_name || (kind==='fallback' ? 'internal_fallback' : ''),
    source_url: srcItem.url || '',
    prompt_version: $('Config').first().json.promptVersion || 'v1',
    claim_sheet: cs
  }
};

// Aggregate packages — emit ONE envelope item. Rows for content_history are
// built by a separate Code node (n8n Code doesn't support multi-output).
const pkgs = $input.all().map(i => i.json);
const upstream = $('When Executed By Workflow').first().json || {};
const first = pkgs[0] || {};
const run_id = first.run_id || upstream.run_id;
const mode = first.mode || upstream.mode;
return [{ json: {
  packages: pkgs,
  run_id,
  mode,
  shortlist: upstream.shortlist || [],
  meta: upstream.meta || {},
  note: upstream.note || '',
  started_at: upstream.started_at || new Date().toISOString()
}}];

// Build one item per package for the content_history Append (autoMap).
const env = $json || {};
const pkgs = env.packages || [];
return pkgs.map(p => ({ json: {
  content_id: p.content_id,
  run_id: p.run_id,
  item_id: p.item_id || '',
  mode: p.mode,
  platform_pair: p.platform_pair,
  status: p.status,
  confidence_label: p.confidence_label,
  instagram_hook:    (p.instagram||{}).hook || '',
  instagram_script:  (p.instagram||{}).script || '',
  instagram_caption: (p.instagram||{}).caption || '',
  instagram_cta:     (p.instagram||{}).cta || '',
  linkedin_post:     (p.linkedin||{}).post || '',
  source_name: p.source_name || '',
  source_url: p.source_url || '',
  prompt_version: p.prompt_version || ''
}}));

// Always expose the envelope as the single terminal output, regardless of how
// many append rows flowed in. Readers: WF1 Call Content Factory node.
return [{ json: $('Aggregate Packages').first().json }];
